import Foundation

public actor CodexActiveAccountMonitor: ActiveAccountMonitoring {
    nonisolated public let vendor: Vendor = .codex

    // 15 s: short enough to react to account switches without hammering the disk.
    public static let defaultInterval: Duration = .seconds(15)

    private let codexHomePath: String?
    private let fileManager: FileManager
    private let logger: FileLogger
    private let interval: Duration
    /// Emits only the stable `account_id` switch signal so callers can invalidate
    /// any derived email cache and force a fresh fetch.
    private let onActiveAccountChanged: (@Sendable (AccountId) async -> Void)?

    private var monitorTask: Task<Void, Never>?
    private var lastObservedAccountId: AccountId?

    public init(
        codexHomePath: String? = nil,
        fileManager: FileManager = .default,
        logger: FileLogger = Loggers.codex,
        interval: Duration = CodexActiveAccountMonitor.defaultInterval,
        onActiveAccountChanged: (@Sendable (AccountId) async -> Void)? = nil
    ) {
        self.codexHomePath = codexHomePath ?? ProcessInfo.processInfo.environment["CODEX_HOME"]
        self.fileManager = fileManager
        self.logger = logger
        self.interval = interval
        self.onActiveAccountChanged = onActiveAccountChanged
    }

    public func start() {
        guard monitorTask == nil else {
            logger.log(.warning, "Codex active-account monitor already running")
            return
        }
        logger.log(.info, "Starting Codex active-account monitor with interval \(interval)")
        monitorTask = Task {
            while !Task.isCancelled {
                await self.checkOnce()
                try? await Task.sleep(for: self.interval)
                guard !Task.isCancelled else { break }
            }
        }
    }

    public func stop() {
        monitorTask?.cancel()
        monitorTask = nil
        logger.log(.info, "Codex active-account monitor stopped")
    }

    public func checkOnce() async {
        guard let accountId = readAccountId() else {
            // Transient state during `codex login` — auth.json may be absent briefly.
            // Only trust positive signals; preserve the previous observed state otherwise.
            logger.log(.debug, "Codex account ID unresolved — keeping previous state")
            return
        }

        let previous = lastObservedAccountId
        lastObservedAccountId = accountId
        // Skip the callback on the first resolution (startup) — only fire on genuine switches.
        if let previous, previous != accountId {
            logger.log(.info, "Codex account switched: \(accountId)")
            await onActiveAccountChanged?(accountId)
        }
    }

    private func readAccountId() -> AccountId? {
        let home = fileManager.homeDirectoryForCurrentUser.path

        var candidates: [String] = []
        if let codexHome = codexHomePath {
            candidates.append("\(codexHome)/auth.json")
        }
        candidates.append("\(home)/.config/codex/auth.json")
        candidates.append("\(home)/.codex/auth.json")

        for path in candidates where fileManager.fileExists(atPath: path) {
            guard let data = fileManager.contents(atPath: path) else { continue }
            let jsonObject: Any
            do {
                jsonObject = try JSONSerialization.jsonObject(with: data)
            } catch {
                logger.log(.debug, "Failed to parse Codex auth at \(path): \(error)")
                continue
            }
            guard let json = jsonObject as? [String: Any],
                  let tokens = json["tokens"] as? [String: Any],
                  let accountId = tokens["account_id"] as? String,
                  !accountId.isEmpty else { continue }
            return AccountId(rawValue: accountId)
        }
        return nil
    }
}

import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// One segment of the menu bar label — a single metric's formatted text, its tier,
/// and whether the leading colored dot should be drawn. Pay-as-you-go segments
/// render without a dot; time-window segments respect the user's `showDot` toggle.
public struct MenuBarSegment: Sendable, Equatable {
    public let text: String
    public let tier: ConsumptionTier?
    public let showDot: Bool
    public let vendorIcon: Vendor?

    public init(text: String, tier: ConsumptionTier?, showDot: Bool, vendorIcon: Vendor? = nil) {
        self.text = text
        self.tier = tier
        self.showDot = showDot
        self.vendorIcon = vendorIcon
    }
}

/// Formats the user-configured menu bar segments. Iterates the segments declared
/// in `AppPreferences.menuBarSegments`, resolves each against the latest usages
/// file contents, and exposes the rendered label text + per-segment payloads.
/// Falls back to `"--"` when no segment can be rendered.
@Observable
@MainActor
public final class UsageStore {
    public private(set) var menuBarText: String = "--"
    public private(set) var menuBarTier: ConsumptionTier?
    public private(set) var menuBarSegments: [MenuBarSegment] = []
    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
    public private(set) var dataProcessedCount: Int = 0
    public private(set) var entries: [VendorUsageEntry] = []
    public private(set) var outagesByVendor: [Vendor: [Outage]] = [:]

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let preferences: any AppPreferences
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let rawPreviewMaxBytes = 200

    private static func rawPreview(_ data: Data) -> String {
        let slice = data.prefix(rawPreviewMaxBytes)
        if let text = String(data: slice, encoding: .utf8) {
            return "utf8:\(text.debugDescription)"
        }
        let hex = slice.map { String(format: "%02x", $0) }.joined()
        return "hex:\(hex)"
    }

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        preferences: (any AppPreferences)? = nil,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        // Default preferences mirror the pre-settings-window behaviour (S + W for
        // currently-active Claude account) so existing callers and tests that
        // don't supply a preferences store still get meaningful output.
        self.preferences = preferences ?? Self.makeDefaultPreferences()
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    private static func makeDefaultPreferences() -> any AppPreferences {
        // Pre-settings-window defaults (S + W for currently-active Claude account).
        // Kept inline so onboarding can ship an empty seed via
        // `MenuBarSegmentsSeeder.defaultSegments()` without breaking tests and
        // callers that rely on `UsageStore` rendering meaningful output without
        // an explicit preferences store.

