    if let secs = limitWindowSeconds {
        duration = DurationMinutes(rawValue: Int(secs) / 60)
    } else {
        duration = fallbackDuration
    }
    return WindowValues(
        percent: UsagePercent(rawValue: Int(usedPercent.rounded())),
        resetAt: resetAt,
        duration: duration
    )
}

