private static func renderTimeWindow(
    display: TimeWindowDisplay,
    vendor: Vendor,
    resetAt: ISODate?,
    windowDuration: DurationMinutes,
    usagePercent: UsagePercent,
    now: Date
) -> MenuBarSegment? {
    // Mirror TimeWindowMetricRow's "isUnknown" semantics so popover and
    // menubar stay consistent: a missing or already-elapsed resetAt means
    // we have no reliable window — neither the percent nor the remaining
    // time should be trusted, both must render as "???".
    let isUnknown = resetAt.flatMap { $0.date.map { now > $0 } } ?? true

    var parts: [String] = []
    if display.showLetter, !display.letter.isEmpty {
        parts.append(display.letter)
    }
    if display.showPercent {
        parts.append(isUnknown ? "???" : formatUsagePercent(usagePercent, mode: display.percentDisplayMode))
    }
    if display.showReset {
        let remaining = (!isUnknown ? resetAt : nil).map {
            formatRemainingTime(
                resetAt: $0,
                now: now,
                hideMinutesWhenOverOneDay: display.hideResetMinutesWhenOverOneDay
            )
        } ?? "???"
        parts.append(remaining)
    }
    let text = parts.joined(separator: " ")

    let tier: ConsumptionTier?
    if display.showDot, !isUnknown, let resetAt {
        let theoretical = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
        tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
            .map { consumptionTier(ratio: $0) }
    } else {
        tier = nil
    }

