@Suite("MenuBarSegmentResolver — unknown window (popover/menubar consistency)")
struct ResolverUnknownWindowTests {
    // The popover row (TimeWindowMetricRow) renders "???" for BOTH the percent
    // and the remaining time whenever resetAt is nil or already elapsed. The
    // menubar segment must mirror that semantic: showing a "1%" or "0%" next
    // to a "???" remaining time is misleading because the percent is just as
    // unreliable as the missing reset date in that state.
    //
    // In particular this guards against the Codex idle-account quirk
    // (see CodexConnectorTests.idleAccountFreshWindowSignatureEmitsNilResetAt):
    // when OpenAI hands back a fresh-untouched-window signature, the connector
    // emits the metric with resetAt: nil but the usagePercent carries the
    // parasitic value (often 1%) the API returned. The popover ignores it,
    // and so must the menubar.

    private static func segment(
        resetAt: ISODate?,
        usagePercent: Int = 1,
        display: TimeWindowDisplay = TimeWindowDisplay(letter: "S")
    ) -> MenuBarSegment? {
        let entry = VendorUsageEntry(
            vendor: .codex,
            account: "user@openai.com",
            isActive: true,
            metrics: [.timeWindow(
                name: "Session (5h)",
                resetAt: resetAt,
                windowDuration: 300,
                usagePercent: UsagePercent(rawValue: usagePercent)
            )]
        )
        let config = MenuBarSegmentConfig(
            vendor: .codex,
            account: .currentlyActive,
            metricName: "Session (5h)",
            display: .timeWindow(display)
        )
        return MenuBarSegmentResolver.resolve(
            config: config,
            entries: [entry],
            now: referenceDate
        ).rendered
    }

    @Test("nil resetAt → menubar renders ??? for percent and reset (matches popover)")
    func nilResetAtRendersAllUnknown() {
        let result = ResolverUnknownWindowTests.segment(resetAt: nil, usagePercent: 1)
        #expect(result?.text == "S ??? ???")
        #expect(result?.tier == nil)
    }

    @Test("elapsed resetAt → menubar renders ??? for percent and reset (matches popover)")
    func elapsedResetAtRendersAllUnknown() {
        // referenceDate is 2026-04-17T12:47:00Z — pick a resetAt well before that.
        let elapsed = ISODate(rawValue: "2026-04-17T10:00:00Z")
        let result = ResolverUnknownWindowTests.segment(resetAt: elapsed, usagePercent: 42)
        #expect(result?.text == "S ??? ???")
        #expect(result?.tier == nil)
    }

    @Test("in-progress resetAt → menubar still renders the percent and remaining time")
    func inProgressResetAtRendersValues() {
        // resetAt 2h 13m after referenceDate
        let active = ISODate(rawValue: "2026-04-17T15:00:00Z")
        let result = ResolverUnknownWindowTests.segment(resetAt: active, usagePercent: 48)
        #expect(result?.text == "S 48% 2h 13m")
    }
}

