                Text(isUnknown ? "???" : formatRemainingTime(resetAt: resetAt!, now: now))
                    .font(.system(size: 10).monospacedDigit())
                    .foregroundStyle(.secondary)
                Spacer()
                Text(isUnknown ? "resets ???" : "resets \(formatResetDate(resetAt!, now: now))")
                    .font(.system(size: 10))
                    .foregroundStyle(.secondary)
