/// Single source of truth for "what does this time-window metric look like
/// right now". Both the popover row and the menubar segment derive their
/// rendering from an instance of this struct, so the two views can never
/// disagree on which parts of a window are trustworthy and which aren't.
/// Any new surface that shows a time-window metric must go through this
/// type as well.
///
/// IMPORTANT semantic: `usagePercent` and `resetAt` are independent pieces
/// of information. A window can have a perfectly meaningful `0%` or `1%`
/// even when its reset date is missing or elapsed — they are NOT the same
/// "unknown". This type only flags the reset side as unknown; the percent
/// is always considered usable and must be rendered verbatim by callers.
public struct TimeWindowVisualState: Sendable, Equatable {
    /// True when `resetAt` is absent, unparseable, or already elapsed.
    /// Only the reset/remaining-time related parts of the UI must surface
    /// "???" in that state — the percent stays meaningful.
    public let resetIsUnknown: Bool
    /// Usage fraction in 0...1. Always reflects `usagePercent` verbatim,
    /// regardless of `resetIsUnknown`.
    public let actualFraction: Double
    /// Elapsed-time fraction of the window in 0...1. Zero when
    /// `resetIsUnknown` is true because the elapsed time can't be computed
    /// without a known window endpoint.
    /// Named `elapsedFraction` to avoid shadowing the free function
    /// `theoreticalFraction(resetAt:windowDuration:now:)`.
    public let elapsedFraction: Double
    /// Severity tier when comparable, `nil` when the window is unknown or
    /// hasn't accumulated enough elapsed time for a ratio. Requires a
    /// known reset so the "actual vs theoretical pace" comparison has meaning.
    public let tier: ConsumptionTier?

    public init(resetAt: ISODate?, windowDuration: DurationMinutes, usagePercent: UsagePercent, now: Date) {
        let actualFraction = Double(usagePercent.rawValue) / 100.0
        self.actualFraction = actualFraction
        if let resetAt, let resetDate = resetAt.date, now <= resetDate {
            self.resetIsUnknown = false
            let elapsed = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
            self.elapsedFraction = elapsed
            self.tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: elapsed)
                .map(consumptionTier(ratio:))
        } else {
            self.resetIsUnknown = true
            self.elapsedFraction = 0
            self.tier = nil
        }
    }
}

